// Star/mark as important - signals to provider this sender is trusted
const email = $input.first().json;

return [{
  json: {
    action: 'marked_important',
    from: email.from,
    subject: email.subject || '',
    messageId: email.messageId || '',
    receivedAt: new Date().toISOString()
  }
}];

// Generate a natural reply to Saima's warmup email

const shortReplies = [
  'Thanks for the update Saima! This looks great. Let me review and get back to you by end of day.',
  'Appreciate you sharing this! I had a few thoughts - can we schedule a quick call to discuss?',
  'Great timing - I was just thinking about this. Let me pull together some notes and circle back.',
  'Thanks Saima! I agree with your approach. Let us move forward with this plan.',
  'This is really helpful, thank you. I will take a closer look and share my feedback tomorrow.',
  'Sounds good to me! I am available Thursday or Friday if you want to sync up.',
  'Perfect, thanks for the follow-up. Everything looks on track from my end as well.',
  'Good stuff! I have a few ideas to add. Will send them over shortly.',
  'Thanks for checking in Saima! Things are going well. Let us catch up next week.',
  'Really appreciate this! The direction looks solid. Happy to discuss further whenever you are free.'
];

const mediumReplies = [
  'Thanks for sending this over Saima! I have had a chance to review the details and overall it looks really solid. I especially like the approach you outlined in the first section.\n\nOne thing I was wondering - have we considered the timeline impact? Might be worth a quick discussion. Let me know when works for you.',
  'Great update Saima! I am glad things are progressing well. I have been working on the related piece on my end and I think our timelines are aligning nicely.\n\nI will have my portion ready by Thursday. Should we plan to combine everything on Friday?',
  'Really appreciate the thorough summary. I had a couple of follow-up thoughts.\n\nFirst, I think the strategy is spot on. Second, we might want to loop in the broader team once we have the draft finalized.\n\nLet me know what you think about the timing.',
  'This is exactly what I was hoping to see. Nice work pulling this together so quickly.\n\nI do have one suggestion. Maybe we should add a brief section covering the competitive landscape. I can draft that part if you would like.\n\nOtherwise I think we are in great shape.',
  'Thanks for the heads up Saima. I just reviewed the changes and they look good to me.\n\nThe feedback you incorporated really strengthened the overall piece. I think we are ready to move to the next phase whenever you are.\n\nShall we aim for Monday?'
];

// 60% short, 40% medium for variety
const useShort = Math.random() < 0.6;
const pool = useShort ? shortReplies : mediumReplies;
const reply = pool[Math.floor(Math.random() * pool.length)];

// Build reply subject
const origSubject = $input.first().json.subject || 'your message';
const replySubject = origSubject.startsWith('Re:') ? origSubject : 'Re: ' + origSubject;

// Extract sender email
const fromField = $input.first().json.from || '';
const match = fromField.match(/<(.+?)>/);
const senderEmail = match ? match[1] : fromField.trim();

return [{
  json: {
    replyTo: senderEmail,
    subject: replySubject,
    body: reply,
    originalMessageId: $input.first().json.messageId || ''
  }
}];

return [{
  json: {
    status: 'REPLY_SENT',
    repliedTo: $input.first().json.replyTo,
    subject: $input.first().json.subject,
    timestamp: new Date().toISOString()
  }
}];
